UPDATE permissions p
SET module = s.module,
    resource = s.resource,
    action = s.action,
    description = s.description,
    is_active = s.is_active,
    updated_at = NOW()
FROM seed s
WHERE p.code = s.code
  AND p.is_deleted = FALSE;

